sql:
SELECT name, price
FROM firearms
WHERE price > 500;

SELECT name
FROM firearms
WHERE magazine_capacity = (SELECT MAX(magazine_capacity) FROM firearms);

SELECT name
FROM firearms
WHERE fire_rate > (SELECT AVG(fire_rate) FROM firearms);

external_knowledge:
- "High overall performance" is defined as an average of accuracy and stability greater than 0.7;
- "Highly rated" means an average rating greater than 4;
- "Popular" means the firearm is marked as a favorite by more than 10 unique users.

- "Most beloved firearms" refers to the firearms with the highest average rating;
- "Shining stars" is a metaphor for the top-rated items;
- "Game universe" refers to the context of each game;
- "Average praise" refers to the average rating given by users.

sql:
SELECT name, price
FROM firearms
ORDER BY price DESC;

external_knowledge:
- "most sought-after" refers to the highest number of access events;
- "highly regarded" refers to the highest average user rating;
- "greatest destructive power" refers to the highest total damage across all ranges and body parts.

sql:
SELECT COUNT(firearm_id) 
FROM firearms 
WHERE price > (SELECT AVG(price) FROM firearms);

SELECT weapon_type_id, AVG(price) AS average_price
FROM firearms
GROUP BY weapon_type_id;

SELECT MAX(total_accesses) AS highest_access_count
FROM (
    SELECT firearm_id, COUNT(access_id) AS total_accesses
    FROM access_logs
    GROUP BY firearm_id
) AS access_counts;

external_knowledge:
- The "number of games" refers to the total number of games each firearm is featured in;
- The "average rating" is the mean rating given by users;
- The "total reviews" is the total number of reviews each firearm has received;
- The "total favorites" is the total number of times each firearm has been marked as a favorite;
- The "last update date" is the most recent date when the firearm's data was updated;
- The "popularity rank" is determined by a combination of the number of games, average rating, total reviews, total favorites, and the last update date.

- "stands out like a shining star" refers to the firearm with the best overall score;
- "balancing its fire rate, price, and magazine capacity" refers to the composite score calculated from these attributes;
- "a favorite among users" refers to the count of times the firearm has been marked as a favorite;
- "frequently featured in games" refers to the count of games the firearm appears in.

sql:
SELECT type_name
FROM weapon_types
ORDER BY type_name;

SELECT 
    AVG(price + fire_rate + magazine_capacity) / 3 AS average_firearm_score
FROM firearms;

external_knowledge:
- "Crown jewel" refers to the most valuable or prized item;
- "Boasting" indicates a high level of achievement or quality;
- "Across all the games it appears in" means considering all the games where the firearm is used.

- "High armor penetration" means the firearm can effectively penetrate armor, making it more effective in combat scenarios;
- "Game count > 2" indicates that the firearm has appeared in at least three different games, suggesting its popularity and versatility;
- "Average damage per reviewer" is calculated by dividing the total damage at range 0 by the number of unique reviewers plus one to avoid division by zero.

sql:
SELECT name, price, magazine_capacity
FROM firearms
ORDER BY magazine_capacity DESC;
